w bij Akismet','On this page, you are able to set up the Akismet plugin.'=>'Op deze pagina kunt u de Akismet-plugin instellen.','Akismet Setup'=>'Akismet-instellingen','Overview'=>'Overzicht','Re-adding...'=>'Opnieuw toevoegen...','(undo)'=>'(ongedaan maken)','URL removed'=>'URL verwijderd','Removing...'=>'Verwijderen...','Remove this URL'=>'Deze URL verwijderen','Akismet'=>'Akismet','Settings'=>'Instellingen','Comment History'=>'Reactiehistorie']];